/* Define a variable font */
@font-face {
  font-family: 'Inter Variable';
  src: url('/fonts/Inter-roman.var.woff2') format('woff2-variations');
  font-weight: 100 900; /* Define the range of available weights */
  font-style: normal;
  font-display: swap;
}

/* Apply variable font settings to different elements */
h1 {
  font-family: 'Inter Variable', sans-serif;
  /* Adjust weight (wght) and width (wdth) axes */
  font-variation-settings: 'wght' 700, 'wdth' 125;
  font-size: clamp(2rem, 5vw + 1rem, 4rem);
  line-height: 1.1;
}

p {
  font-family: 'Inter Variable', sans-serif;
  font-variation-settings: 'wght' 400, 'wdth' 100;
  font-size: 1.125rem;
  max-width: 70ch;
}
